136	    stact.sa_flags = SA_RESTART;
137	    sigaction(SIGCHLD, &stact, NULL);
138	
139	    // ignore opencore signal handler
140	    for (int i = 0; i < kNumHandledSignals; i++)
141	        sigaction(kExceptionSignals[i], &stact, NULL);
142	}
